// Split flags so we can ship real curvature data without forcing real
// elevation data (or vice versa) — empty arrays just fall back to the
// in-code keyframe path for that channel.
const HAS_REAL_CURVES = !!geoData?.curves?.length && geoData.curves.length >= 100;
const HAS_REAL_HILLS  = !!geoData?.hills?.length  && geoData.hills.length  >= 100;
const HAS_REAL_GEO    = HAS_REAL_CURVES || HAS_REAL_HILLS;  // legacy alias

